6	const prompt = 'A cute baby sea otter';
7	
8	function createBasicModel({
9	  headers,
10	  fetch,
11	  currentDate,
12	}: {
13	  headers?: Record<string, string | undefined>;
14	  fetch?: FetchFunction;
15	  currentDate?: () => Date;
16	  settings?: any;
17	} = {}) {
18	  return new FalImageModel('fal-ai/qwen-image', {
19	    provider: 'fal.image',
20	    baseURL: 'https://api.example.com',
21	    headers: headers ?? { 'api-key': 'test-key' },
22	    fetch,
23	    _internal: {
24	      currentDate,
25	    },
26	  });
27	}
