32	      response: {
33	        type: 'json-value',
34	        body: {
35	          images: [
36	            {
37	              url: 'https://api.example.com/image.png',
38	              width: 1024,
39	              height: 1024,
40	              content_type: 'image/png',
41	            },
42	          ],
43	        },
44	      },
45	    },
