import {
  InvalidArgumentError,
  LanguageModelV3,
  NoSuchModelError,
  ProviderV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  generateId,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { VERSION } from './version';
import { AnthropicMessagesLanguageModel } from './anthropic-messages-language-model';
import { AnthropicMessagesModelId } from './anthropic-messages-options';
import { anthropicTools } from './anthropic-tools';

// Provider interface - extends ProviderV3
export interface AnthropicProvider extends ProviderV3 {
  (modelId: AnthropicMessagesModelId): LanguageModelV3;
  languageModel(modelId: AnthropicMessagesModelId): LanguageModelV3;
  chat(modelId: AnthropicMessagesModelId): LanguageModelV3;
  messages(modelId: AnthropicMessagesModelId): LanguageModelV3;
  textEmbeddingModel(modelId: string): never;
  tools: typeof anthropicTools;
}

// Settings interface for customization
export interface AnthropicProviderSettings {
  baseURL?: string;
  apiKey?: string;
  authToken?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  generateId?: () => string;
  name?: string;
}

// Factory function
export function createAnthropic(
  options: AnthropicProviderSettings = {},
): AnthropicProvider {
  // Load and configure base URL
  const baseURL = withoutTrailingSlash(...) ?? 'https://api.anthropic.com/v1';

  // Get headers with auth
  const getHeaders = () => { ... };

  // Create language model factory
  const createChatModel = (modelId: AnthropicMessagesModelId) =>
    new AnthropicMessagesLanguageModel(modelId, { ... });

  // Create provider object
  const provider = function (modelId: AnthropicMessagesModelId) {
    if (new.target) {
      throw new Error('Cannot use with new keyword');
    }
    return createChatModel(modelId);
  };

  // Attach methods to provider function
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.messages = createChatModel;
  provider.imageModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'imageModel' });
  };
  provider.tools = anthropicTools;

  return provider;
}

// Default singleton instance
export const anthropic = createAnthropic();
```

**Key patterns:**
- Provider extends `ProviderV3` interface
- Factory function returns callable object with methods
- Settings interface for customization
- Default singleton instance exported
- Error handling for unsupported model types

