32	const FLUX_2_MODEL_PATTERN = /^black-forest-labs\/flux-2-/;
33	const MAX_FLUX_2_INPUT_IMAGES = 8;
34	
35	export class ReplicateImageModel implements ImageModelV3 {
36	  readonly specificationVersion = 'v3';
37	
38	  get maxImagesPerCall(): number {
39	    // Flux-2 models support up to 8 input images
40	    return this.isFlux2Model ? MAX_FLUX_2_INPUT_IMAGES : 1;
41	  }
42	
43	  get provider(): string {
44	    return this.config.provider;
45	  }
