```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import { FetchFunction, loadApiKey, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /** API key; defaults to PIXELART_API_KEY env var */
  apiKey?: string;
  /** Base URL override; default: https://api.pixelart.ai/v1 */
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): PixelArtImageModel;
  imageModel(modelId: PixelArtImageModelId): PixelArtImageModel;
  languageModel(modelId: string): never;
  embeddingModel(modelId: string): never;
  textEmbeddingModel(modelId: string): never;
}

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart',
      baseURL: options.baseURL ?? 'https://api.pixelart.ai/v1',
      headers: getHeaders,
      fetch: options.fetch,
    });

  const unsupported = (modelId: string, modelType: string) => {
    throw new NoSuchModelError({ modelId, modelType });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => unsupported(modelId, 'languageModel') as never,
    embeddingModel: (modelId: string) => unsupported(modelId, 'embeddingModel') as never,
    textEmbeddingModel: (modelId: string) => unsupported(modelId, 'textEmbeddingModel') as never,
  };
}

export const pixelart = createPixelArt();
```

