158	          prompt,
159	          aspect_ratio: aspectRatio,
160	          size,
161	          seed,
162	          num_outputs: n,
163	          ...imageInputs,
164	          ...(maskInput != null ? { mask: maskInput } : {}),
165	          ...inputOptions,
166	        },
