│   ├── {provider}-speech-settings.ts (speech model IDs - FAL only)
│   ├── {provider}-transcription-model.ts (transcription - FAL only)
│   ├── {provider}-transcription-options.ts (transcription model IDs - FAL only)
│   ├── {provider}-config.ts (config interface - FAL only)
│   ├── {provider}-api-types.ts (API type definitions - FAL only)
│   ├── version.ts (version constant)
│   ├── *.test.ts (unit tests)
│   └── __fixtures__/ (test fixtures)
