  });

  it('should not include maxWaitTimeInSeconds in request body', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
