import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it, vi } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt } from './pixelart-provider';

vi.mock('./version', () => ({
  VERSION: '0.0.0-test',
}));

const TEST_BASE64 = Buffer.from('test-image-data').toString('base64');
const TEST_IMAGE_BYTES = new Uint8Array(Buffer.from('test-image-data'));
const prompt = 'A pixelated dragon breathing fire';

const provider = createPixelArt({ apiKey: 'test-api-key' });
const model = provider.image('pixelart-v1');

describe('doGenerate', () => {
  const testDate = new Date(2024, 0, 1);
  const server = createTestServer({
    'https://api.pixelart.ai/*': {
      response: {
        type: 'json-value',
        body: { images: [{ b64_json: TEST_BASE64 }] },
      },
    },
  });

  it('should call the correct URL', async () => {
    await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(server.calls[0].requestMethod).toStrictEqual('POST');
    expect(server.calls[0].requestUrl).toStrictEqual(
      'https://api.pixelart.ai/v1/images/generate',
    );
  });

  it('should pass prompt, n, size, and seed in the request body', async () => {
    await model.doGenerate({
      prompt,
      n: 2,
      size: '512x512',
      aspectRatio: undefined,
      seed: 42,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      prompt,
      n: 2,
      size: '512x512',
      seed: 42,
    });
  });

  it('should include style from providerOptions in the request body', async () => {
    await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {
        pixelart: { style: 'retro' },
      },
      files: undefined,
      mask: undefined,
    });

    expect(await server.calls[0].requestBodyJson).toMatchObject({
      style: 'retro',
    });
  });

  it('should include pixelDensity as pixel_density in the request body', async () => {
    await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {
        pixelart: { pixelDensity: 64 },
      },
      files: undefined,
      mask: undefined,
    });

    expect(await server.calls[0].requestBodyJson).toMatchObject({
      pixel_density: 64,
    });
  });

  it('should emit an unsupported warning for aspectRatio', async () => {
    const result = await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: '16:9',
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.warnings).toStrictEqual([
      { type: 'unsupported', feature: 'aspectRatio' },
    ]);
  });

  it('should pass the Authorization header and user-agent', async () => {
    const customProvider = createPixelArt({
      apiKey: 'test-api-key',
      headers: { 'X-Custom-Header': 'custom-value' },
    });

    await customProvider.image('pixelart-v1').doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      headers: { 'X-Request-Header': 'req-value' },
      files: undefined,
      mask: undefined,
    });

    expect(server.calls[0].requestHeaders).toMatchObject({
      authorization: 'Bearer test-api-key',
      'x-custom-header': 'custom-value',
      'x-request-header': 'req-value',
    });
    expect(server.calls[0].requestUserAgent).toContain(
      'ai-sdk/pixelart/0.0.0-test',
    );
  });

  it('should decode base64 images and return Uint8Array', async () => {
    const result = await model.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.images).toHaveLength(1);
    expect(result.images[0]).toStrictEqual(TEST_IMAGE_BYTES);
  });

  it('should return response metadata with timestamp and modelId', async () => {
    const modelWithTimestamp = new PixelArtImageModel('pixelart-v2', {
      provider: 'pixelart',
      baseURL: 'https://api.pixelart.ai/v1',
      headers: { Authorization: 'Bearer test-api-key' },
      _internal: { currentDate: () => testDate },
    });

    const result = await modelWithTimestamp.doGenerate({
      prompt,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.response).toStrictEqual({
      timestamp: testDate,
      modelId: 'pixelart-v2',
      headers: expect.any(Object),
    });
  });

  it('should report maxImagesPerCall as 4', () => {
    expect(model.maxImagesPerCall).toBe(4);
  });

  it('should handle multiple images in the response', async () => {
    const secondBase64 = Buffer.from('second-image-data').toString('base64');
    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'json-value',
      body: {
        images: [{ b64_json: TEST_BASE64 }, { b64_json: secondBase64 }],
      },
    };

    const result = await model.doGenerate({
      prompt,
      n: 2,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      files: undefined,
      mask: undefined,
    });

    expect(result.images).toHaveLength(2);
    expect(result.images[0]).toStrictEqual(TEST_IMAGE_BYTES);
    expect(result.images[1]).toStrictEqual(
      new Uint8Array(Buffer.from('second-image-data')),
    );
  });
});

